class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        def is_palindrome(i, j, s):
            while i < j:
                if s[i] != s[j]:
                    return False
                i += 1
                j -= 1
            return True

        def check(a, b):
            i, j = 0, len(a) - 1
            while i < j:
                if a[i] != b[j]:
                    return is_palindrome(i, j, a) or is_palindrome(i, j, b)
                i += 1
                j -= 1
            return True

        return check(a, b) or check(b, a)
```
